// Build People.ai export query for meetings in the last 24 hours
// At 9am: catches yesterday afternoon meetings (4h+ delay means they're ready)
// At 3pm: catches this morning's meetings (ended by 11am, 4h+ elapsed)
const now = Date.now();
const twentyFourHoursAgo = now - 24 * 60 * 60 * 1000;

const query = {
  object: "activity",
  filter: {
    "$and": [
      { attribute: { slug: "ootb_activity_type" }, clause: { "$eq": "meeting" } },
      { attribute: { slug: "ootb_activity_external" }, clause: { "$eq": true } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$gte": twentyFourHoursAgo } },
      { attribute: { slug: "ootb_activity_timestamp" }, clause: { "$lte": now } }
    ]
  },
  columns: [
    { slug: "ootb_activity_uid" },
    { slug: "ootb_activity_timestamp" },
    { slug: "ootb_activity_subject" },
    { slug: "ootb_activity_originator" },
    { slug: "ootb_activity_account_name" },
    { slug: "ootb_activity_opportunity_name" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_email" },
    { slug: "ootb_activity_participants", variation_id: "ootb_activity_participants_name" }
  ],
  sort: [{ attribute: { slug: "ootb_activity_timestamp" }, direction: "desc" }]
};

return [{ json: { query: JSON.stringify(query) } }];

// Parse CSV response from People.ai meetings export
// API returns human-readable headers: "Activity", "Activity date", "Subject",
// "Account Name", "Opportunity Name", "Activity Participants (Email)", etc.
const raw = $('Fetch Today Meetings').first().json.data || '';
if (!raw || raw.trim().length === 0) {
  return [{ json: { meetings: [], meetingCount: 0 } }];
}

const lines = raw.split('\n');
if (lines.length < 2) {
  return [{ json: { meetings: [], meetingCount: 0 } }];
}

// Parse CSV header
const headerLine = lines[0];
const headers = [];
let field = '';
let inQuotes = false;
for (let i = 0; i < headerLine.length; i++) {
  const c = headerLine[i];
  if (c === '"') { inQuotes = !inQuotes; }
  else if (c === ',' && !inQuotes) { headers.push(field.trim()); field = ''; }
  else { field += c; }
}
headers.push(field.trim());

// Parse CSV rows
function parseCSVRow(line) {
  const fields = [];
  let f = '';
  let q = false;
  for (let i = 0; i < line.length; i++) {
    const c = line[i];
    if (c === '"') {
      if (q && i + 1 < line.length && line[i + 1] === '"') { f += '"'; i++; }
      else { q = !q; }
    } else if (c === ',' && !q) { fields.push(f.trim()); f = ''; }
    else { f += c; }
  }
  fields.push(f.trim());
  return fields;
}

// Flexible header matching: check multiple possible names
function getVal(row, ...names) {
  for (const name of names) {
    const idx = headers.findIndex(h => h.toLowerCase().includes(name.toLowerCase()));
    if (idx >= 0 && row[idx]) return row[idx];
  }
  return '';
}

// Parse bracket-delimited list: "[a;b;c]" → ["a","b","c"]
function parseList(val) {
  if (!val) return [];
  return val.replace(/^\[/, '').replace(/\]$/, '').trim()
    .split(';').map(s => s.trim()).filter(Boolean);
}

const meetings = [];
for (let i = 1; i < lines.length; i++) {
  if (!lines[i].trim()) continue;
  const row = parseCSVRow(lines[i]);

  // Match actual API headers: "Activity date", "Activity", "Subject", etc.
  const tsRaw = getVal(row, 'Activity date', 'date', 'timestamp');
  let tsMs = 0;
  if (tsRaw) {
    const num = Number(tsRaw);
    if (!isNaN(num) && num > 1e12) { tsMs = num; }
    else {
      const parsed = new Date(tsRaw);
      if (!isNaN(parsed.getTime())) tsMs = parsed.getTime();
    }
  }
  if (!tsMs || isNaN(tsMs)) continue;

  const activityUid = getVal(row, 'Activity') || '';
  // Skip if no UID (first column "Activity" contains the UID)
  if (!activityUid) continue;

  const participantEmails = parseList(getVal(row, 'Participants (Email)', 'Participants'));
  const participantNames = parseList(getVal(row, 'Participants (Name)'));

  meetings.push({
    activityUid,
    timestamp: tsMs,
    subject: getVal(row, 'Subject'),
    originator: getVal(row, 'Originator'),
    accountName: getVal(row, 'Account Name', 'Account'),
    accountId: '',
    opportunityName: getVal(row, 'Opportunity Name', 'Opportunity'),
    participants: participantEmails.join('; '),
    participantEmails,
    participantNames,
  });
}

return [{ json: { meetings, meetingCount: meetings.length, headers } }];

// Match users to meetings that ended 4+ hours ago (transcript available)
// CRITICAL: Only include meetings where the user is a PARTICIPANT
// Group by user: output ONE item per user with all their ready meetings
const meetings = $('Parse Meetings').first().json.meetings || [];
const usersAll = $('Get Followup Users').all().map(i => i.json);
const sentAll = $('Check Sent Followups').all().map(i => i.json);

// Filter valid users
const users = usersAll.filter(u => u && u.id && u.onboarding_state === 'complete');

// Build dedup set: userId:activityUid
const sentSet = new Set();
for (const msg of sentAll) {
  if (msg && msg.metadata) {
    try {
      const meta = typeof msg.metadata === 'string' ? JSON.parse(msg.metadata) : msg.metadata;
      if (meta.activity_uid && msg.user_id) {
        sentSet.add(msg.user_id + ':' + meta.activity_uid);
      }
    } catch(e) {}
  }
}

const now = Date.now();
const MEETING_DURATION_MS = 60 * 60 * 1000; // assume 60 min meetings
const MIN_ELAPSED_MS = 4 * 60 * 60 * 1000;  // 4 hours after meeting end

const output = [];

for (const user of users) {
  const followupEnabled = user.followup_enabled !== false;
  if (!followupEnabled) continue;

  const userEmail = (user.email || '').toLowerCase();
  if (!userEmail) continue;

  const repName = userEmail
    .split('@')[0].split('.').map(w => w.charAt(0).toUpperCase() + w.slice(1)).join(' ');

  const readyMeetings = [];

  for (const meeting of meetings) {
    // Only include meetings this user attended
    const participantEmails = (meeting.participantEmails || []).map(e => e.toLowerCase());
    if (!participantEmails.includes(userEmail)) continue;

    const estimatedEnd = meeting.timestamp + MEETING_DURATION_MS;
    const timeSinceEnd = now - estimatedEnd;

    if (timeSinceEnd < MIN_ELAPSED_MS) continue;

    const dedupKey = user.id + ':' + meeting.activityUid;
    if (sentSet.has(dedupKey)) continue;

    if (!meeting.accountName) continue;

    const tz = 'America/Los_Angeles';
    const meetingDate = new Date(meeting.timestamp);
    const timeStr = meetingDate.toLocaleTimeString('en-US', { timeZone: tz, hour: 'numeric', minute: '2-digit' });
    const dayStr = meetingDate.toLocaleDateString('en-US', { timeZone: tz, weekday: 'short' });
    const hoursAgo = Math.round(timeSinceEnd / 3600000);

    readyMeetings.push({
      activityUid: meeting.activityUid,
      subject: meeting.subject || '[no subject]',
      accountName: meeting.accountName,
      accountId: meeting.accountId || '',
      opportunityName: meeting.opportunityName || '',
      participants: meeting.participants || '',
      timestamp: meeting.timestamp,
      timeStr,
      dayStr,
      hoursAgo,
    });
  }

  if (readyMeetings.length === 0) continue;

  readyMeetings.sort((a, b) => b.timestamp - a.timestamp);

  output.push({
    json: {
      userId: user.id,
      slackUserId: user.slack_user_id,
      email: user.email,
      repName,
      assistantName: user.assistant_name || 'Aria',
      assistantEmoji: user.assistant_emoji || ':robot_face:',
      organizationId: user.organization_id,
      meetings: readyMeetings,
      meetingCount: readyMeetings.length,
    }
  });
}

if (output.length === 0) {
  return [{ json: { noMatches: true } }];
}

return output;

