  assistant_name: data.assistantName,
  assistant_emoji: data.assistantEmoji,
});

blocks.push({
  type: "actions",
  elements: [
    {
      type: "button",
      text: { type: "plain_text", text: ":salesforce: Review & Log", emoji: true },
      style: "primary",
      action_id: "recap_save_activity",
      value: savePayload
    },
    {
      type: "button",
      text: { type: "plain_text", text: ":email: Draft Follow-up", emoji: true },
      action_id: "recap_draft_followup",
      value: draftPayload
    },
    ...(taskCount > 0 ? [{
      type: "button",
      text: { type: "plain_text", text: `:memo: Tasks (${taskCount})`, emoji: true },
      action_id: "recap_view_tasks",
      value: JSON.stringify({
        account_name: m.accountName,
        meeting_subject: m.subject,
